// One-off: screenshot the self-contained print/PDF document produced by
// tine-core's page_print_html (generated by the ignored `gen_sample_export` test
// at /tmp/tine-sample-export/print-sample.html). Renders with BOTH Chromium and
// WebKit (the engine family Tine's WebKitGTK belongs to — reveals Inter-ligature /
// font garble Chromium hides) and in BOTH light and dark color schemes (the PDF
// must stay light even when the OS is dark).
import { chromium, webkit } from "playwright";
import { pathToFileURL } from "node:url";

const src = process.argv[2] || "/tmp/tine-sample-export/print-sample.html";
const outDir = "/tmp/claude-3042/-aux-koutecky-logseq/5a8edc2b-663a-4ee8-b183-325ec619c4d9/scratchpad";

for (const [name, type] of [["chromium", chromium], ["webkit", webkit]]) {
  let browser;
  try {
    browser = await type.launch();
  } catch (e) {
    console.log(`skip ${name}: ${String(e).split("\n")[0]}`);
    continue;
  }
  for (const scheme of ["light", "dark"]) {
    const page = await browser.newPage({ viewport: { width: 820, height: 1100 }, colorScheme: scheme });
    await page.goto(pathToFileURL(src).href, { waitUntil: "networkidle" });
    await page.waitForTimeout(1200);
    await page.emulateMedia({ media: "print", colorScheme: scheme });
    await page.waitForTimeout(200);
    await page.screenshot({ path: `${outDir}/printdoc-${name}-${scheme}.png`, fullPage: true });
    await page.close();
  }
  await browser.close();
  console.log(`wrote printdoc-${name}-{light,dark}.png`);
}
